const getSantoDoDiaCompleto = (day, month) => {
  const key = `${day}-${month}`;
  if (SANTOS_FIXOS[key]) return SANTOS_FIXOS[key];
  // Fallback rotativo
  return FALLBACK_SANTOS[(day + month) % FALLBACK_SANTOS.length];
};

