  drawWrappedText(ctx, `"${texto}"`, W/2, 720, W-200, 80, "#fff", "italic bold 56px 'Sora', sans-serif");

  // Referência
  ctx.fillStyle = theme.accent;
  ctx.textAlign = "center";
